private Product getProductAndCache(Long id) {  
    Product product = null;  
    // 键存在，返回值  
    if (cache.containsKey(id)) {  
        product = cache.get(id);  
    } else {  
        // 键不存在，则获取值  
        // 需要遍历数据源查询获得 Product  
        for (Product p : ProductGetData()) {  
            if (p.getId().equals(id)) {  
                product = p;  
                break;  
            }  
        }  
        // 加入 ConcurrentHashMap  
        if (product != null) {  
            cache.put(id, product);  
        }  
    }  
    return product;  
}

